import { ExternalTokenizer } from '@lezer/lr';

import { characterCodes } from '../character-codes.js';
import { InclusionOperator } from '../parser.terms.js';

const { EOF, SPACE, OPENING_BRACKET, CLOSING_BRACKET, DOUBLEQUOTE, BACKSLASH } =
  characterCodes;

// Valid input after a logical operator. Every other input will result in the
// token not being accepted.
const validAfterInclusionOperator = [
  OPENING_BRACKET,
  CLOSING_BRACKET,
  DOUBLEQUOTE,
  BACKSLASH,
  SPACE,
  EOF,
];

/** @internal */
export const inclusionOperatorTokenizer = new ExternalTokenizer(
  (inputStream) => {
    const char = String.fromCharCode(inputStream.next).toLowerCase();
    let tokenOffset = 0;

    // Only if the current character is an 'i' (in) or 'n' (not in), the token may be a valid InclusionOperator.
    switch (char) {
      case 'i':
        // Input stream matches 'in'.
        if (String.fromCharCode(inputStream.peek(1)).toLowerCase() === 'n') {
          tokenOffset = 2;
        }
        break;
      case 'n':
        // Input stream matches 'not in'.
        if (
          // TODO: switch to match sequence.
          // matchCharacterSequence({inputStream, characterSequence: 'not in'})
          String.fromCharCode(inputStream.peek(1)).toLowerCase() === 'o' &&
          String.fromCharCode(inputStream.peek(2)).toLowerCase() === 't' &&
          String.fromCharCode(inputStream.peek(3)).toLowerCase() === ' ' &&
          String.fromCharCode(inputStream.peek(4)).toLowerCase() === 'i' &&
          String.fromCharCode(inputStream.peek(5)).toLowerCase() === 'n'
        ) {
          tokenOffset = 6;
        }
        break;
      default:
        // Early exit. Input doesn't match an InclusionOperator.
        return;
    }

    // Advance to the last character of the token.
    inputStream.advance(tokenOffset);

    // Check, if the next character is a valid character after an InclusionOperator.
    // If yes, accept the token, excluding the next character to only match the exact token.
    if (validAfterInclusionOperator.includes(inputStream.next)) {
      inputStream.acceptToken(InclusionOperator);
    }
  },
);
